        import sailpoint.object.QueryOptions;
        import sailpoint.object.Filter;
        import sailpoint.object.Identity;
        import sailpoint.tools.Util;
        import java.util.List;
		     
        Identity currentManagerObject=context.getObjectByName(Identity.class,currentManager);
        Identity newManager=context.getObjectByName(Identity.class,proposedManager);
        if(currentManagerObject!=null && newManager!=null){
          workflow.put("proposedManagerEmail",newManager.getEmail());
          workflow.put("currentManagerEmail",currentManagerObject.getEmail());
          boolean noneSelected=false;
          List finalUsersList=new ArrayList();
          if(allReportees!=null && allReportees==true){
            Filter filterInactive=Filter.eq("inactive",false);
            Filter filterManager=Filter.eq("manager.name",currentManager);
            QueryOptions qo=new QueryOptions();
            qo.addFilter(filterInactive);
            qo.addFilter(filterManager);
            Iterator itr=context.search(Identity.class,qo);
            while(itr!=null && itr.hasNext()){
              Identity reportee=(Identity) itr.next();
              if(reportee!=null){
                finalUsersList.add(reportee);
              }
            }
            Util.flushIterator(itr);
          }
          else if(selectedReportees!=null && !selectedReportees.isEmpty()){
            for(String user:selectedReportees){
              Identity selectedReportee=context.getObjectById(Identity.class,user);
              if(selectedReportee!=null){
                finalUsersList.add(selectedReportee);
              }
            }
          }
          workflow.put("finalUsersList",finalUsersList);
          if(finalUsersList==null || finalUsersList.isEmpty()){
            noneSelected=true;
          }  
          workflow.put("noneSelected",noneSelected);
          int count=0;
          for(Identity finalReportee: finalUsersList){
            finalReportee.setManager(newManager);
            context.saveObject(finalReportee);
            if(count%50 == 0){
              context.commitTransaction();
            }
            count++;
          }
          context.commitTransaction();
        }

 import sailpoint.object.Identity;

 List userList=new ArrayList();
 
List tempUserList=workflow.get("finalUsersList");
 if(tempUserList!=null){
	 for(Identity user: tempUserList){
		 userList.add(user.getDisplayName());	
	}
 }
 return userList;

        import javax.faces.application.FacesMessage; 
        import sailpoint.tools.Util;
        List currentMessages = httpSession.getAttribute("sailpoint.web.PageCodeBase.sessionMessages");  
        FacesMessage myMessage = null;
        if(!noneSelected){
					String message = "Manager change successful for selected reportees";
					myMessage = new FacesMessage(FacesMessage.SEVERITY_INFO,message+".","Success");  
        }
        else{
					String message = "No Reportees Selected";
					myMessage = new FacesMessage(FacesMessage.SEVERITY_ERROR,message+".","Failure"); 
        }
        List myMessages = new ArrayList();  
        myMessages.add(myMessage);  
        httpSession.setAttribute("sailpoint.web.PageCodeBase.sessionMessages", myMessages);
